if ('onloadend' in request) {
  // Use onloadend if available
  request.onloadend = onloadend;
} else {
  // Listen for ready state to emulate onloadend
  request.onreadystatechange = function handleLoad() {
    if (!request || request.readyState !== 4) {
      return;
    }

    // The request errored out and we didn't get a response, this will be
    // handled by onerror instead
    // With one exception: request that using file: protocol, most browsers
    // will return status as 0 even though it's a successful request
    if (
      request.status === 0 &&
      !(request.responseURL && request.responseURL.startsWith('file:'))
    ) {
      return;
    }
    // readystate handler is calling before onerror or ontimeout handlers,
    // so we should call onloadend on the next 'tick'
    setTimeout(onloadend);
  };
}

class QuerySelectorItem {
  constructor (node) {
    // all enumerable properties from the target
    Object.assign(this, node.target.package)

    // append extra info
    this.pkgid = node.target.pkgid
    this.location = node.target.location
    this.path = node.target.path
    this.realpath = node.target.realpath
    this.resolved = node.target.resolved
    this.from = []
    this.to = []
    this.dev = node.target.dev
    this.inBundle = node.target.inBundle
    this.deduped = this.from.length > 1
    this.overridden = node.overridden
    this.queryContext = node.queryContext
    for (const edge of node.target.edgesIn) {
      this.from.push(edge.from.location)
    }
    for (const [, edge] of node.target.edgesOut) {
      if (edge.to) {
        this.to.push(edge.to.location)
      }
    }
  }
}

if (this.requests[name]?.length) {
  debug('removeSocket, have a request, make a socket');
  req = this.requests[name][0];
} else {
  // TODO(rickyes): this logic will not be FIFO across origins.
  // There might be older requests in a different origin, but
  // if the origin which releases the socket has pending requests
  // that will be prioritized.
  const keys = ObjectKeys(this.requests);
  for (let i = 0; i < keys.length; i++) {
    const prop = keys[i];
    // Check whether this specific origin is already at maxSockets
    if (this.sockets[prop]?.length) break;
    debug('removeSocket, have a request with different origin,' +
      ' make a socket');
    req = this.requests[prop][0];
    options = req[kRequestOptions];
    break;
  }
}

if (patched) {
  const wrapped = Module.wrap(content);
  const script = makeContextifyScript(
    wrapped,                 // code
    filename,                // filename
    0,                       // lineOffset
    0,                       // columnOffset
    undefined,               // cachedData
    false,                   // produceCachedData
    undefined,               // parsingContext
    hostDefinedOptionId,     // hostDefinedOptionId
    importModuleDynamically, // importModuleDynamically
  );

  // Cache the source map for the module if present.
  const { sourceMapURL, sourceURL } = script;
  if (sourceMapURL) {
    maybeCacheSourceMap(filename, content, cjsModuleInstance, false, sourceURL, sourceMapURL);
  }

  return {
    __proto__: null,
    function: runScriptInThisContext(script, true, false),
    sourceMapURL,
  };
}

if (isAborted(fetchParams)) {
  // 1. Set response’s aborted flag.
  response.aborted = true

  // 2. If stream is readable, then error stream with the result of
  //    deserialize a serialized abort reason given fetchParams’s
  //    controller’s serialized abort reason and an
  //    implementation-defined realm.
  if (isReadable(stream)) {
    fetchParams.controller.controller.error(
      fetchParams.controller.serializedAbortReason
    )
  }
} else {
  // 3. Otherwise, if stream is readable, error stream with a TypeError.
  if (isReadable(stream)) {
    fetchParams.controller.controller.error(new TypeError('terminated', {
      cause: isErrorLike(reason) ? reason : undefined
    }))
  }
}

if (isBuildingSnapshot()) {
  addSerializeCallback(() => {
    // Clear the cached certs so that they are reloaded at runtime.
    // Bundled certificates are immutable so they are spared.
    extraCACertificates = undefined;
    systemCACertificates = undefined;
    if (hasResetDefaultCACertificates) {
      defaultCACertificates = undefined;
    }
  });
  addDeserializeCallback(() => {
    // If the tls module is loaded during snapshotting, load the certificates from
    // various sources again at runtime so that by the time an actual TLS connection is
    // made, the loading is done. If the default CA certificates have been overridden, then
    // the serialized overriding certificates are likely to be used and pre-loading
    // from the sources would probably not yield any benefit, so skip it.
    if (!hasResetDefaultCACertificates) {
      startLoadingCertificatesOffThread();
    }
  });
}
